145	// executeOnService dispatches against a pre-built svc using the durable
146	// knobs from rcfg and per-invocation plumbing from runtime, then records
147	// one session-index row. It is the inlined replacement for the retired
148	// RunViaServiceWith helper and is shared with dispatchViaResolvedConfig.
149	func executeOnService(ctx context.Context, svc agentlib.FizeauService, workDir string, rcfg config.ResolvedConfig, runtime AgentRunRuntime) (*Result, error) {
150		if svc == nil {
151			return nil, fmt.Errorf("agent: nil service")
152		}
153		if ctx == nil {
154			ctx = context.Background()
155		}
156	
157		promptText := runtime.Prompt
158		if runtime.PromptFile != "" {
159			data, err := readPromptFileBounded(runtime.PromptFile)
160			if err != nil {
161				return nil, fmt.Errorf("agent: read prompt file: %w", err)
162			}
163			promptText = string(data)
164		}
165		if promptText == "" {
166			return nil, fmt.Errorf("agent: prompt is required")
167		}
168	
169		wd := runtime.WorkDir
170		if wd == "" {
171			wd = workDir
172		}
173		if wd == "" {
174			wd, _ = os.Getwd()
175		}
176	
177		idle := rcfg.Timeout()
178		if idle <= 0 {
179			idle = time.Duration(DefaultTimeoutMS) * time.Millisecond
180		}
181		wall := rcfg.WallClock()
182		if wall <= 0 {
183			wall = time.Duration(DefaultWallClockMS) * time.Millisecond
184		}
185	
186		sessionLogDir := runtime.SessionLogDirOverride
187		if sessionLogDir == "" {
188			sessionLogDir = rcfg.SessionLogDir()
189		}
190		if sessionLogDir == "" {
191			sessionLogDir = ResolveLogDir(workDir, "")
192		}
193	
194		pt := rcfg.Passthrough()
195	
196		harness := runtime.HarnessOverride
197		if harness == "" && !runtime.ClearRoutingPins {
198			harness = pt.Harness
199		}
200	
201		model := runtime.ModelOverride
202		if model == "" && !runtime.ClearRoutingPins {
203			model = pt.Model
204		}
205	
206		provider := runtime.ProviderOverride
207		if provider == "" && !runtime.ClearRoutingPins {
208			provider = pt.Provider
209		}
210		if runtime.ClearRoutingPins && runtime.ProviderOverride == "" {
211			provider = ""
212		}
213	
214		profile := runtime.ProfileOverride
215		if profile == "" && !runtime.ClearProfile {
216			profile = rcfg.Profile()
217		}
218	
219		permissions := runtime.PermissionsOverride
