316			result.Output = final.FinalText
317			if final.Usage != nil {
318				// v0.9.1: Usage fields became *int (nullable).
319				if final.Usage.InputTokens != nil {
320					result.InputTokens = *final.Usage.InputTokens
321				}
322				if final.Usage.OutputTokens != nil {
323					result.OutputTokens = *final.Usage.OutputTokens
324				}
325				if final.Usage.TotalTokens != nil {
326					result.Tokens = *final.Usage.TotalTokens
327				}
328			}
329			if final.CostUSD > 0 {
330				result.CostUSD = final.CostUSD
331			}
332			result.ExitCode = final.ExitCode
333			result.Error = final.Error
334			if final.RoutingActual != nil {
335				if result.Provider == "" {
336					result.Provider = final.RoutingActual.Provider
337				}
338				if final.RoutingActual.Model != "" {
339					result.Model = final.RoutingActual.Model
340				}
341				if final.RoutingActual.Harness != "" {
342					result.Harness = final.RoutingActual.Harness
343				}
344				if final.RoutingActual.Power > 0 {
345					result.ActualPower = final.RoutingActual.Power
346				}
347			}
348			if final.SessionLogPath != "" {
349				result.AgentSessionID = final.SessionLogPath
350			}
351		}
352		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
353		normalizeServiceFinalExitCode(result)
354		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
355			Harness:     harness,
356			Model:       model,
357			Provider:    provider,
358			Effort:      rcfg.Effort(),
359			Correlation: runtime.Correlation,
360		}, result, start, finishedAt)
361		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
362		return result, nil
363	}
