365	func metadataWithEnv(metadata, env map[string]string) map[string]string {
366		if len(metadata) == 0 && len(env) == 0 {
367			return nil
368		}
369		out := make(map[string]string, len(metadata)+len(env))
370		for k, v := range metadata {
371			out[k] = v
372		}
373		for k, v := range env {
374			out[k] = v
375		}
376		return out
377	}
