388	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
389	// querying the service's ListHarnesses and (best-effort) the harness registry.
390	// It is the production replacement for Runner.Capabilities.
391	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
392		if ctx == nil {
393			ctx = context.Background()
394		}
395		svc, err := resolveService(workDir)
396		if err != nil {
397			return nil, fmt.Errorf("agent: build service: %w", err)
398		}
399		infos, err := svc.ListHarnesses(ctx)
400		if err != nil {
401			return nil, fmt.Errorf("agent: list harnesses: %w", err)
402		}
403		var info *agentlib.HarnessInfo
404		for i := range infos {
405			if infos[i].Name == harnessName {
406				info = &infos[i]
407				break
408			}
409		}
410		if info == nil {
411			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
412		}
413	
414		// Pull binary and reasoning-level metadata from the local registry — the
415		// service does not expose these directly today.
416		registry := newHarnessRegistry()
417		harness, _ := registry.Get(harnessName)
418	
419		caps := &HarnessCapabilities{
420			Harness:             info.Name,
421			Available:           info.Available,
422			Binary:              harness.Binary,
423			Path:                info.Path,
424			Surface:             harness.Surface,
425			CostClass:           info.CostClass,
426			IsLocal:             info.CostClass == "local",
427			ExactPinSupport:     info.ExactPinSupport,
428			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
429			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
430		}
431		if len(info.SupportedReasoning) > 0 {
432			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
433		} else if len(harness.ReasoningLevels) > 0 {
434			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
435		}
436	
437		if harness.DefaultModel != "" {
438			caps.Model = harness.DefaultModel
439			caps.Models = []string{harness.DefaultModel}
440		}
441	
442		return caps, nil
443	}
