445	// TestProviderConnectivityViaService runs a HealthCheck against the named
446	// harness and translates the result into a ProviderStatus. It is the
447	// production replacement for Runner.TestProviderConnectivity.
448	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
449		status := ProviderStatus{Reachable: false}
450		if ctx == nil {
451			ctx = context.Background()
452		}
453		if harnessName == "virtual" || harnessName == "agent" {
454			status.Reachable = true
455			status.CreditsOK = true
456			return status
457		}
458		svc, err := resolveService(workDir)
459		if err != nil {
460			status.Error = err.Error()
461			return status
462		}
463		if timeout > 0 {
464			var cancel context.CancelFunc
465			ctx, cancel = context.WithTimeout(ctx, timeout)
466			defer cancel()
467		}
468		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
469			errStr := strings.ToLower(err.Error())
470			status.Error = err.Error()
471			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
472				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
473				status.CreditsOK = false
474			}
475			return status
476		}
477		status.Reachable = true
478		status.CreditsOK = true
479		return status
480	}
